SELECT s.id, s.customer_id, s.total_amount, s.total_cost, s.sale_date, c.name AS customer_name, c.gender AS customer_gender FROM sales s, customers c WHERE s.customer_id = c.id
AND s.customer_id = #{customerId}
AND s.sale_date BETWEEN #{startDate} AND #{endDate}
ORDER BY s.sale_date DESC

SELECT si.*, b.title AS book_title
FROM sale_items si, books b
WHERE si.book_id = b.id AND si.id = #{itemId}

mapper.update:
UPDATE sale_items
SET quantity = #{quantity}, unit_price = #{unitPrice},
    subtotal = #{unitPrice} * #{quantity}
WHERE id = #{id}
